        return {
            'homeassistant/components/elkm1/__init__.py': '"""Support the ElkM1 Gold and ElkM1 EZ8 alarm/integration panels."""\n\nfrom __future__ import annotations\n\nimport asyncio\nimport logging\nimport re\nfrom typing import Any\n\nfrom elkm1_lib.elements import Element\nfrom elkm1_lib.elk import Elk\nfrom elkm1_lib.util import parse_url\nimport voluptuous as vol\n\nfrom homeassistant.config_entries import SOURCE_IMPORT, ConfigEntry\nfrom homeassistant.const import (\n    CONF_ENABLED,\n    CONF_EXCLUDE,\n    CONF_HOST,\n    CONF_INCLUDE,\n    CONF_PASSWORD,\n    CONF_PREFIX,\n    CONF_TEMPERATURE_UNIT,\n    CONF_USERNAME,\n    CONF_ZONE,\n    Platform,\n    UnitOfTemperature,\n)\nfrom homeassistant.core import HomeAssistant, callback\nfrom homeassistant.exceptions import ConfigEntryNotReady\nfrom homeassistant.helpers import config_validation as cv\nfrom homeassistant.helpers.event import async_track_time_interval\nfrom homeassistant.helpers.typing import ConfigType\nfrom homeassistant.util.network import is_ip_address\n\nfrom .const import (\n    ATTR_KEY,\n    ATTR_KEY_NAME,\n    ATTR_KEYPAD_ID,\n    ATTR_KEYPAD_NAME,\n    CONF_AREA,\n    CONF_AUTO_CONFIGURE,\n    CONF_COUNTER,\n    CONF_KEYPAD,\n    CONF_OUTPUT,\n    CONF_PLC,\n    CONF_SETTING,\n    CONF_TASK,\n    CONF_THERMOSTAT,\n    DISCOVER_SCAN_TIMEOUT,\n    DISCOVERY_INTERVAL,\n    DOMAIN,\n    ELK_ELEMENTS,\n    EVENT_ELKM1_KEYPAD_KEY_PRESSED,\n    LOGIN_TIMEOUT,\n)\nfrom .discovery import (\n    async_discover_device,\n    async_discover_devices,\n    async_trigger_discovery,\n    async_update_entry_from_discovery,\n)\nfrom .models import ELKM1Data\nfrom .services import async_setup_services\n\ntype ElkM1ConfigEntry = ConfigEntry[ELKM1Data]\n\nSYNC_TIMEOUT = 120\n\n_LOGGER = logging.getLogger(__name__)\n\nPLATFORMS = [\n    Platform.ALARM_CONTROL_PANEL,\n    Platform.BINARY_SENSOR,\n    Platform.CLIMATE,\n    Platform.LIGHT,\n    Platform.SCENE,\n    Platform.SENSOR,\n    Platform.SWITCH,\n]\n\n\ndef hostname_from_url(url: str) -> str:\n    """Return the hostname from a url."""\n    return parse_url(url)[1]\n\n\ndef _host_validator(config: dict[str, str]) -> dict[str, str]:\n    """Validate that a host is properly configured."""\n    if config[CONF_HOST].startswith(("elks://", "elksv1_2://")):\n        if CONF_USERNAME not in config or CONF_PASSWORD not in config:\n            raise vol.Invalid(\n                "Specify username and password for elks:// or elksv1_2://"\n            )\n    elif not config[CONF_HOST].startswith("elk://") and not config[\n        CONF_HOST\n    ].startswith("serial://"):\n        raise vol.Invalid("Invalid host URL")\n    return config\n\n\ndef _elk_range_validator(rng: str) -> tuple[int, int]:\n    def _housecode_to_int(val: str) -> int:\n        match = re.search(r"^([a-p])(0[1-9]|1[0-6]|[1-9])$", val.lower())\n        if match:\n            return (ord(match.group(1)) - ord("a")) * 16 + int(match.group(2))\n        raise vol.Invalid("Invalid range")\n\n    def _elk_value(val: str) -> int:\n        return int(val) if val.isdigit() else _housecode_to_int(val)\n\n    vals = [s.strip() for s in str(rng).split("-")]\n    start = _elk_value(vals[0])\n    end = start if len(vals) == 1 else _elk_value(vals[1])\n    return (start, end)\n\n\ndef _has_all_unique_prefixes(value: list[dict[str, str]]) -> list[dict[str, str]]:\n    """Validate that each m1 configured has a unique prefix.\n\n    Uniqueness is determined case-independently.\n    """\n    prefixes = [device[CONF_PREFIX] for device in value]\n    schema = vol.Schema(vol.Unique())\n    schema(prefixes)\n    return value\n\n\nDEVICE_SCHEMA_SUBDOMAIN = vol.Schema(\n    {\n        vol.Optional(CONF_ENABLED, default=True): cv.boolean,\n        vol.Optional(CONF_INCLUDE, default=[]): [_elk_range_validator],\n        vol.Optional(CONF_EXCLUDE, default=[]): [_elk_range_validator],\n    }\n)\n\nDEVICE_SCHEMA = vol.All(\n    cv.deprecated(CONF_TEMPERATURE_UNIT),\n    vol.Schema(\n        {\n            vol.Required(CONF_HOST): cv.string,\n            vol.Optional(CONF_PREFIX, default=""): vol.All(cv.string, vol.Lower),\n            vol.Optional(CONF_USERNAME, default=""): cv.string,\n            vol.Optional(CONF_PASSWORD, default=""): cv.string,\n            vol.Optional(CONF_AUTO_CONFIGURE, default=False): cv.boolean,\n            vol.Optional(CONF_TEMPERATURE_UNIT, default="F"): cv.temperature_unit,\n            vol.Optional(CONF_AREA, default={}): DEVICE_SCHEMA_SUBDOMAIN,\n            vol.Optional(CONF_COUNTER, default={}): DEVICE_SCHEMA_SUBDOMAIN,\n            vol.Optional(CONF_KEYPAD, default={}): DEVICE_SCHEMA_SUBDOMAIN,\n            vol.Optional(CONF_OUTPUT, default={}): DEVICE_SCHEMA_SUBDOMAIN,\n            vol.Optional(CONF_PLC, default={}): DEVICE_SCHEMA_SUBDOMAIN,\n            vol.Optional(CONF_SETTING, default={}): DEVICE_SCHEMA_SUBDOMAIN,\n            vol.Optional(CONF_TASK, default={}): DEVICE_SCHEMA_SUBDOMAIN,\n            vol.Optional(CONF_THERMOSTAT, default={}): DEVICE_SCHEMA_SUBDOMAIN,\n            vol.Optional(CONF_ZONE, default={}): DEVICE_SCHEMA_SUBDOMAIN,\n        },\n    ),\n    _host_validator,\n)\n\nCONFIG_SCHEMA = vol.Schema(\n    {DOMAIN: vol.All(cv.ensure_list, [DEVICE_SCHEMA], _has_all_unique_prefixes)},\n    extra=vol.ALLOW_EXTRA,\n)\n\n\nasync def async_setup(hass: HomeAssistant, hass_config: ConfigType) -> bool:\n    """Set up the Elk M1 platform."""\n    async_setup_services(hass)\n\n    async def _async_discovery(*_: Any) -> None:\n        async_trigger_discovery(\n            hass, await async_discover_devices(hass, DISCOVER_SCAN_TIMEOUT)\n        )\n\n    hass.async_create_background_task(_async_discovery(), "elkm1 setup discovery")\n    async_track_time_interval(\n        hass, _async_discovery, DISCOVERY_INTERVAL, cancel_on_shutdown=True\n    )\n\n    if DOMAIN not in hass_config:\n        return True\n\n    for index, conf in enumerate(hass_config[DOMAIN]):\n        _LOGGER.debug("Importing elkm1 #%d - %s", index, conf[CONF_HOST])\n\n        # The update of the config entry is done in async_setup\n        # to ensure the entry if updated before async_setup_entry\n        # is called to avoid a situation where the user has to restart\n        # twice for the changes to take effect\n        current_config_entry = _async_find_matching_config_entry(\n            hass, conf[CONF_PREFIX]\n        )\n        if current_config_entry:\n            # If they alter the yaml config we import the changes\n            # since there currently is no practical way to do an options flow\n            # with the large amount of include/exclude/enabled options that elkm1 has.\n            hass.config_entries.async_update_entry(current_config_entry, data=conf)\n            continue\n\n        hass.async_create_task(\n            hass.config_entries.flow.async_init(\n                DOMAIN,\n                context={"source": SOURCE_IMPORT},\n                data=conf,\n            )\n        )\n\n    return True\n\n\n@callback\ndef _async_find_matching_config_entry(\n    hass: HomeAssistant, prefix: str\n) -> ConfigEntry | None:\n    for entry in hass.config_entries.async_entries(DOMAIN):\n        if entry.unique_id == prefix:\n            return entry\n    return None\n\n\nasync def async_setup_entry(hass: HomeAssistant, entry: ElkM1ConfigEntry) -> bool:\n    """Set up Elk-M1 Control from a config entry."""\n    conf = entry.data\n\n    host = hostname_from_url(entry.data[CONF_HOST])\n\n    _LOGGER.debug("Setting up elkm1 %s", conf["host"])\n\n    if (not entry.unique_id or ":" not in entry.unique_id) and is_ip_address(host):\n        _LOGGER.debug(\n            "Unique id for %s is missing during setup, trying to fill from discovery",\n            host,\n        )\n        if device := await async_discover_device(hass, host):\n            async_update_entry_from_discovery(hass, entry, device)\n\n    config: dict[str, Any] = {}\n\n    if not conf[CONF_AUTO_CONFIGURE]:\n        # With elkm1-lib==0.7.16 and later auto configure is available\n        config["panel"] = {"enabled": True, "included": [True]}\n        for item, max_ in ELK_ELEMENTS.items():\n            config[item] = {\n                "enabled": conf[item][CONF_ENABLED],\n                "included": [not conf[item]["include"]] * max_,\n            }\n            try:\n                _included(conf[item]["include"], True, config[item]["included"])\n                _included(conf[item]["exclude"], False, config[item]["included"])\n            except (ValueError, vol.Invalid) as err:\n                _LOGGER.error("Config item: %s; %s", item, err)\n                return False\n\n    elk = Elk(\n        {\n            "url": conf[CONF_HOST],\n            "userid": conf[CONF_USERNAME],\n            "password": conf[CONF_PASSWORD],\n        }\n    )\n    elk.connect()\n\n    def _keypad_changed(keypad: Element, changeset: dict[str, Any]) -> None:\n        if (keypress := changeset.get("last_keypress")) is None:\n            return\n\n        hass.bus.async_fire(\n            EVENT_ELKM1_KEYPAD_KEY_PRESSED,\n            {\n                ATTR_KEYPAD_NAME: keypad.name,\n                ATTR_KEYPAD_ID: keypad.index + 1,\n                ATTR_KEY_NAME: keypress[0],\n                ATTR_KEY: keypress[1],\n            },\n        )\n\n    for keypad in elk.keypads:\n        keypad.add_callback(_keypad_changed)\n\n    try:\n        if not await async_wait_for_elk_to_sync(elk, LOGIN_TIMEOUT, SYNC_TIMEOUT):\n            return False\n    except TimeoutError as exc:\n        raise ConfigEntryNotReady(f"Timed out connecting to {conf[CONF_HOST]}") from exc\n\n    elk_temp_unit = elk.panel.temperature_units\n    if elk_temp_unit == "C":\n        temperature_unit = UnitOfTemperature.CELSIUS\n    else:\n        temperature_unit = UnitOfTemperature.FAHRENHEIT\n    config["temperature_unit"] = temperature_unit\n    prefix: str = conf[CONF_PREFIX]\n    auto_configure: bool = conf[CONF_AUTO_CONFIGURE]\n    entry.runtime_data = ELKM1Data(\n        elk=elk,\n        prefix=prefix,\n        mac=entry.unique_id,\n        auto_configure=auto_configure,\n        config=config,\n        keypads={},\n    )\n\n    await hass.config_entries.async_forward_entry_setups(entry, PLATFORMS)\n\n    return True\n\n\ndef _included(ranges: list[tuple[int, int]], set_to: bool, values: list[bool]) -> None:\n    for rng in ranges:\n        if not rng[0] <= rng[1] <= len(values):\n            raise vol.Invalid(f"Invalid range {rng}")\n        values[rng[0] - 1 : rng[1]] = [set_to] * (rng[1] - rng[0] + 1)\n\n\nasync def async_unload_entry(hass: HomeAssistant, entry: ElkM1ConfigEntry) -> bool:\n    """Unload a config entry."""\n    unload_ok = await hass.config_entries.async_unload_platforms(entry, PLATFORMS)\n    # disconnect cleanly\n    entry.runtime_data.elk.disconnect()\n    return unload_ok\n\n\nasync def async_wait_for_elk_to_sync(\n    elk: Elk,\n    login_timeout: int,\n    sync_timeout: int,\n) -> bool:\n    """Wait until the elk has finished sync. Can fail login or timeout."""\n\n    sync_event = asyncio.Event()\n    login_event = asyncio.Event()\n\n    success = True\n\n    def login_status(succeeded: bool) -> None:\n        nonlocal success\n\n        success = succeeded\n        if succeeded:\n            _LOGGER.debug("ElkM1 login succeeded")\n            login_event.set()\n        else:\n            elk.disconnect()\n            _LOGGER.error("ElkM1 login failed; invalid username or password")\n            login_event.set()\n            sync_event.set()\n\n    def sync_complete() -> None:\n        sync_event.set()\n\n    elk.add_handler("login", login_status)\n    elk.add_handler("sync_complete", sync_complete)\n    for name, event, timeout in (\n        ("login", login_event, login_timeout),\n        ("sync_complete", sync_event, sync_timeout),\n    ):\n        _LOGGER.debug("Waiting for %s event for %s seconds", name, timeout)\n        try:\n            async with asyncio.timeout(timeout):\n                await event.wait()\n        except TimeoutError:\n            _LOGGER.debug("Timed out waiting for %s event", name)\n            elk.disconnect()\n            raise\n        _LOGGER.debug("Received %s event", name)\n\n    return success\n',
            'homeassistant/components/elkm1/config_flow.py': '"""Config flow for Elk-M1 Control integration."""\n\nfrom __future__ import annotations\n\nimport logging\nfrom typing import Any, Self\n\nfrom elkm1_lib.discovery import ElkSystem\nfrom elkm1_lib.elk import Elk\nimport voluptuous as vol\n\nfrom homeassistant.config_entries import ConfigFlow, ConfigFlowResult\nfrom homeassistant.const import (\n    CONF_ADDRESS,\n    CONF_HOST,\n    CONF_PASSWORD,\n    CONF_PREFIX,\n    CONF_PROTOCOL,\n    CONF_USERNAME,\n)\nfrom homeassistant.exceptions import HomeAssistantError\nfrom homeassistant.helpers import device_registry as dr\nfrom homeassistant.helpers.service_info.dhcp import DhcpServiceInfo\nfrom homeassistant.helpers.typing import DiscoveryInfoType, VolDictType\nfrom homeassistant.util import slugify\nfrom homeassistant.util.network import is_ip_address\n\nfrom . import async_wait_for_elk_to_sync, hostname_from_url\nfrom .const import CONF_AUTO_CONFIGURE, DISCOVER_SCAN_TIMEOUT, DOMAIN, LOGIN_TIMEOUT\nfrom .discovery import (\n    _short_mac,\n    async_discover_device,\n    async_discover_devices,\n    async_update_entry_from_discovery,\n)\n\nCONF_DEVICE = "device"\n\nNON_SECURE_PORT = 2101\nSECURE_PORT = 2601\nSTANDARD_PORTS = {NON_SECURE_PORT, SECURE_PORT}\n\n_LOGGER = logging.getLogger(__name__)\n\nPROTOCOL_MAP = {\n    "secure": "elks://",\n    "TLS 1.2": "elksv1_2://",\n    "non-secure": "elk://",\n    "serial": "serial://",\n}\n\n\nVALIDATE_TIMEOUT = 35\n\nBASE_SCHEMA: VolDictType = {\n    vol.Optional(CONF_USERNAME, default=""): str,\n    vol.Optional(CONF_PASSWORD, default=""): str,\n}\n\nSECURE_PROTOCOLS = ["secure", "TLS 1.2"]\nALL_PROTOCOLS = [*SECURE_PROTOCOLS, "non-secure", "serial"]\nDEFAULT_SECURE_PROTOCOL = "secure"\nDEFAULT_NON_SECURE_PROTOCOL = "non-secure"\n\nPORT_PROTOCOL_MAP = {\n    NON_SECURE_PORT: DEFAULT_NON_SECURE_PROTOCOL,\n    SECURE_PORT: DEFAULT_SECURE_PROTOCOL,\n}\n\n\nasync def validate_input(data: dict[str, str], mac: str | None) -> dict[str, str]:\n    """Validate the user input allows us to connect.\n\n    Data has the keys from DATA_SCHEMA with values provided by the user.\n    """\n    userid = data.get(CONF_USERNAME)\n    password = data.get(CONF_PASSWORD)\n\n    prefix = data[CONF_PREFIX]\n    url = _make_url_from_data(data)\n    requires_password = url.startswith(("elks://", "elksv1_2"))\n\n    if requires_password and (not userid or not password):\n        raise InvalidAuth\n\n    elk = Elk(\n        {"url": url, "userid": userid, "password": password, "element_list": ["panel"]}\n    )\n    elk.connect()\n\n    try:\n        if not await async_wait_for_elk_to_sync(elk, LOGIN_TIMEOUT, VALIDATE_TIMEOUT):\n            raise InvalidAuth\n    finally:\n        elk.disconnect()\n\n    short_mac = _short_mac(mac) if mac else None\n    if prefix and prefix != short_mac:\n        device_name = prefix\n    elif mac:\n        device_name = f"ElkM1 {short_mac}"\n    else:\n        device_name = "ElkM1"\n    return {"title": device_name, CONF_HOST: url, CONF_PREFIX: slugify(prefix)}\n\n\ndef _address_from_discovery(device: ElkSystem) -> str:\n    """Append the port only if its non-standard."""\n    if device.port in STANDARD_PORTS:\n        return device.ip_address\n    return f"{device.ip_address}:{device.port}"\n\n\ndef _make_url_from_data(data: dict[str, str]) -> str:\n    if host := data.get(CONF_HOST):\n        return host\n\n    protocol = PROTOCOL_MAP[data[CONF_PROTOCOL]]\n    address = data[CONF_ADDRESS]\n    return f"{protocol}{address}"\n\n\ndef _get_protocol_from_url(url: str) -> str:\n    """Get protocol from URL. Returns the configured protocol from URL or the default secure protocol."""\n    return next(\n        (k for k, v in PROTOCOL_MAP.items() if url.startswith(v)),\n        DEFAULT_SECURE_PROTOCOL,\n    )\n\n\ndef _placeholders_from_device(device: ElkSystem) -> dict[str, str]:\n    return {\n        "mac_address": _short_mac(device.mac_address),\n        "host": _address_from_discovery(device),\n    }\n\n\nclass Elkm1ConfigFlow(ConfigFlow, domain=DOMAIN):\n    """Handle a config flow for Elk-M1 Control."""\n\n    VERSION = 1\n\n    host: str | None = None\n\n    def __init__(self) -> None:\n        """Initialize the elkm1 config flow."""\n        self._discovered_device: ElkSystem | None = None\n        self._discovered_devices: dict[str, ElkSystem] = {}\n\n    async def async_step_dhcp(\n        self, discovery_info: DhcpServiceInfo\n    ) -> ConfigFlowResult:\n        """Handle discovery via dhcp."""\n        self._discovered_device = ElkSystem(\n            discovery_info.macaddress, discovery_info.ip, 0\n        )\n        _LOGGER.debug("Elk discovered from dhcp: %s", self._discovered_device)\n        return await self._async_handle_discovery()\n\n    async def async_step_integration_discovery(\n        self, discovery_info: DiscoveryInfoType\n    ) -> ConfigFlowResult:\n        """Handle integration discovery."""\n        self._discovered_device = ElkSystem(\n            discovery_info["mac_address"],\n            discovery_info["ip_address"],\n            discovery_info["port"],\n        )\n        _LOGGER.debug(\n            "Elk discovered from integration discovery: %s", self._discovered_device\n        )\n        return await self._async_handle_discovery()\n\n    async def _async_handle_discovery(self) -> ConfigFlowResult:\n        """Handle any discovery."""\n        device = self._discovered_device\n        assert device is not None\n        mac = dr.format_mac(device.mac_address)\n        host = device.ip_address\n        await self.async_set_unique_id(mac)\n        for entry in self._async_current_entries(include_ignore=False):\n            if (\n                entry.unique_id == mac\n                or hostname_from_url(entry.data[CONF_HOST]) == host\n            ):\n                if async_update_entry_from_discovery(self.hass, entry, device):\n                    self.hass.config_entries.async_schedule_reload(entry.entry_id)\n                return self.async_abort(reason="already_configured")\n        self.host = host\n        if self.hass.config_entries.flow.async_has_matching_flow(self):\n            return self.async_abort(reason="already_in_progress")\n        # Handled ignored case since _async_current_entries\n        # is called with include_ignore=False\n        self._abort_if_unique_id_configured()\n        if not device.port:\n            if discovered_device := await async_discover_device(self.hass, host):\n                self._discovered_device = discovered_device\n            else:\n                return self.async_abort(reason="cannot_connect")\n        return await self.async_step_discovery_confirm()\n\n    def is_matching(self, other_flow: Self) -> bool:\n        """Return True if other_flow is matching this flow."""\n        return other_flow.host == self.host\n\n    async def async_step_discovery_confirm(\n        self, user_input: dict[str, Any] | None = None\n    ) -> ConfigFlowResult:\n        """Confirm discovery."""\n        assert self._discovered_device is not None\n        self.context["title_placeholders"] = _placeholders_from_device(\n            self._discovered_device\n        )\n        return await self.async_step_discovered_connection()\n\n    async def async_step_reconfigure(\n        self, user_input: dict[str, Any] | None = None\n    ) -> ConfigFlowResult:\n        """Handle reconfiguration of the integration."""\n        errors: dict[str, str] = {}\n        reconfigure_entry = self._get_reconfigure_entry()\n        existing_data = reconfigure_entry.data\n\n        if user_input is not None:\n            validate_input_data = dict(user_input)\n            validate_input_data[CONF_PREFIX] = existing_data.get(CONF_PREFIX, "")\n\n            try:\n                info = await validate_input(\n                    validate_input_data, reconfigure_entry.unique_id\n                )\n            except TimeoutError:\n                errors["base"] = "cannot_connect"\n            except InvalidAuth:\n                errors[CONF_PASSWORD] = "invalid_auth"\n            except Exception:\n                _LOGGER.exception("Unexpected exception during reconfiguration")\n                errors["base"] = "unknown"\n            else:\n                # Discover the device at the provided address to obtain its MAC (unique_id)\n                device = await async_discover_device(\n                    self.hass, validate_input_data[CONF_ADDRESS]\n                )\n                if device is not None and device.mac_address:\n                    await self.async_set_unique_id(dr.format_mac(device.mac_address))\n                    self._abort_if_unique_id_mismatch()  # aborts if user tried to switch devices\n                else:\n                    # If we cannot confirm identity, keep existing behavior (don\'t block reconfigure)\n                    await self.async_set_unique_id(reconfigure_entry.unique_id)\n\n                return self.async_update_reload_and_abort(\n                    reconfigure_entry,\n                    data_updates={\n                        **reconfigure_entry.data,\n                        CONF_HOST: info[CONF_HOST],\n                        CONF_USERNAME: validate_input_data[CONF_USERNAME],\n                        CONF_PASSWORD: validate_input_data[CONF_PASSWORD],\n                        CONF_PREFIX: info[CONF_PREFIX],\n                    },\n                    reason="reconfigure_successful",\n                )\n\n        return self.async_show_form(\n            step_id="reconfigure",\n            data_schema=vol.Schema(\n                {\n                    vol.Optional(\n                        CONF_USERNAME,\n                        default=existing_data.get(CONF_USERNAME, ""),\n                    ): str,\n                    vol.Optional(\n                        CONF_PASSWORD,\n                        default="",\n                    ): str,\n                    vol.Required(\n                        CONF_ADDRESS,\n                        default=hostname_from_url(existing_data[CONF_HOST]),\n                    ): str,\n                    vol.Required(\n                        CONF_PROTOCOL,\n                        default=_get_protocol_from_url(existing_data[CONF_HOST]),\n                    ): vol.In(ALL_PROTOCOLS),\n                }\n            ),\n            errors=errors,\n        )\n\n    async def async_step_user(\n        self, user_input: dict[str, Any] | None = None\n    ) -> ConfigFlowResult:\n        """Handle the initial step."""\n        if user_input is not None:\n            if mac := user_input[CONF_DEVICE]:\n                await self.async_set_unique_id(mac, raise_on_progress=False)\n                self._discovered_device = self._discovered_devices[mac]\n                return await self.async_step_discovered_connection()\n            return await self.async_step_manual_connection()\n\n        current_unique_ids = self._async_current_ids(include_ignore=False)\n        current_hosts = {\n            hostname_from_url(entry.data[CONF_HOST])\n            for entry in self._async_current_entries(include_ignore=False)\n        }\n        discovered_devices = await async_discover_devices(\n            self.hass, DISCOVER_SCAN_TIMEOUT\n        )\n        self._discovered_devices = {\n            dr.format_mac(device.mac_address): device for device in discovered_devices\n        }\n        devices_name: dict[str | None, str] = {\n            mac: f"{_short_mac(device.mac_address)} ({device.ip_address})"\n            for mac, device in self._discovered_devices.items()\n            if mac not in current_unique_ids and device.ip_address not in current_hosts\n        }\n        if not devices_name:\n            return await self.async_step_manual_connection()\n        devices_name[None] = "Manual Entry"\n        return self.async_show_form(\n            step_id="user",\n            data_schema=vol.Schema({vol.Required(CONF_DEVICE): vol.In(devices_name)}),\n        )\n\n    async def _async_create_or_error(\n        self, user_input: dict[str, Any], importing: bool\n    ) -> tuple[dict[str, str] | None, ConfigFlowResult | None]:\n        """Try to connect and create the entry or error."""\n        if self._url_already_configured(_make_url_from_data(user_input)):\n            return None, self.async_abort(reason="address_already_configured")\n\n        try:\n            info = await validate_input(user_input, self.unique_id)\n        except TimeoutError as ex:\n            _LOGGER.debug("Connection timed out: %s", ex)\n            return {"base": "cannot_connect"}, None\n        except InvalidAuth as ex:\n            _LOGGER.debug("Invalid auth for %s: %s", user_input.get(CONF_HOST), ex)\n            return {CONF_PASSWORD: "invalid_auth"}, None\n        except Exception:\n            _LOGGER.exception("Unexpected error validating input")\n            return {"base": "unknown"}, None\n\n        if importing:\n            return None, self.async_create_entry(title=info["title"], data=user_input)\n\n        return None, self.async_create_entry(\n            title=info["title"],\n            data={\n                CONF_HOST: info[CONF_HOST],\n                CONF_USERNAME: user_input[CONF_USERNAME],\n                CONF_PASSWORD: user_input[CONF_PASSWORD],\n                CONF_AUTO_CONFIGURE: True,\n                CONF_PREFIX: info[CONF_PREFIX],\n            },\n        )\n\n    async def async_step_discovered_connection(\n        self, user_input: dict[str, Any] | None = None\n    ) -> ConfigFlowResult:\n        """Handle connecting the device when we have a discovery."""\n        errors: dict[str, str] | None = {}\n        device = self._discovered_device\n        assert device is not None\n        if user_input is not None:\n            user_input[CONF_ADDRESS] = _address_from_discovery(device)\n            if self._async_current_entries():\n                user_input[CONF_PREFIX] = _short_mac(device.mac_address)\n            else:\n                user_input[CONF_PREFIX] = ""\n            errors, result = await self._async_create_or_error(user_input, False)\n            if result is not None:\n                return result\n\n        default_proto = PORT_PROTOCOL_MAP.get(device.port, DEFAULT_SECURE_PROTOCOL)\n        return self.async_show_form(\n            step_id="discovered_connection",\n            data_schema=vol.Schema(\n                {\n                    **BASE_SCHEMA,\n                    vol.Required(CONF_PROTOCOL, default=default_proto): vol.In(\n                        ALL_PROTOCOLS\n                    ),\n                }\n            ),\n            errors=errors,\n            description_placeholders=_placeholders_from_device(device),\n        )\n\n    async def async_step_manual_connection(\n        self, user_input: dict[str, Any] | None = None\n    ) -> ConfigFlowResult:\n        """Handle connecting the device when we need manual entry."""\n        errors: dict[str, str] | None = {}\n        if user_input is not None:\n            # We might be able to discover the device via directed UDP\n            # in case its on another subnet\n            if device := await async_discover_device(\n                self.hass, user_input[CONF_ADDRESS]\n            ):\n                await self.async_set_unique_id(\n                    dr.format_mac(device.mac_address), raise_on_progress=False\n                )\n                self._abort_if_unique_id_configured()\n                # Ignore the port from discovery since its always going to be\n                # 2601 if secure is turned on even though they may want insecure\n                user_input[CONF_ADDRESS] = device.ip_address\n            errors, result = await self._async_create_or_error(user_input, False)\n            if result is not None:\n                return result\n\n        return self.async_show_form(\n            step_id="manual_connection",\n            data_schema=vol.Schema(\n                {\n                    **BASE_SCHEMA,\n                    vol.Required(CONF_ADDRESS): str,\n                    vol.Optional(CONF_PREFIX, default=""): str,\n                    vol.Required(\n                        CONF_PROTOCOL, default=DEFAULT_SECURE_PROTOCOL\n                    ): vol.In(ALL_PROTOCOLS),\n                }\n            ),\n            errors=errors,\n        )\n\n    async def async_step_import(self, import_data: dict[str, Any]) -> ConfigFlowResult:\n        """Handle import."""\n        _LOGGER.debug("Elk is importing from yaml")\n        url = _make_url_from_data(import_data)\n\n        if self._url_already_configured(url):\n            return self.async_abort(reason="address_already_configured")\n\n        host = hostname_from_url(url)\n        _LOGGER.debug(\n            "Importing is trying to fill unique id from discovery for %s", host\n        )\n        if (\n            host\n            and is_ip_address(host)\n            and (device := await async_discover_device(self.hass, host))\n        ):\n            await self.async_set_unique_id(\n                dr.format_mac(device.mac_address), raise_on_progress=False\n            )\n            self._abort_if_unique_id_configured()\n\n        errors, result = await self._async_create_or_error(import_data, True)\n        if errors:\n            return self.async_abort(reason=list(errors.values())[0])\n        assert result is not None\n        return result\n\n    def _url_already_configured(self, url: str) -> bool:\n        """See if we already have a elkm1 matching user input configured."""\n        existing_hosts = {\n            hostname_from_url(entry.data[CONF_HOST])\n            for entry in self._async_current_entries()\n        }\n        return hostname_from_url(url) in existing_hosts\n\n\nclass InvalidAuth(HomeAssistantError):\n    """Error to indicate there is invalid auth."""\n',
        }
